#!/usr/bin/perl
use CGI;
use LWP::UserAgent;
use URI::Escape;

# Get the URI of the page we want to redirect to from the
# 'next' parameter, and escape it for use in a URL.
$next = $CGI->param('next');
$next =~ s/\n//g;  # Remove newlines before escaping.
$escaped_uri = uri_escape($next);

# Get the redirect URL by concatenating the base URL with the escaped URI of our target page, and then escape it for use in a URL.
$redirect_url = $CGI->config('server_name') . '/' . $escaped_uri;
$redirect_url =~ s/\n//g;  # Remove newlines before escaping.
$redirect_url = uri_escape($redirect_url);

# Print out the redirect header and the user's target URL, which is now escaped for use in a URL.
print "Location: $redirect_url\n\n";